code_after:
private static long decodeLong(byte[] packed) {
    assert packed.length >= 1 && packed.length <= Long.BYTES;
    long result = (byte) (packed[0] ^ 0x80);
    for (int i = 1; i < packed.length; i++) {
      result = (result << 8) | (packed[i] & 0xFF);
    }
    return result;
  }
